// Parse the Ramsisa schedule CSV into one item per visit.
//
// CSV columns emitted by the Ramsisa engine:
//   date, order, location_id, location_name, territory, tier
// The engine does not emit a per-visit time, so all tasks are scheduled at
// 09:00 local on the visit date. Adjust `DEFAULT_TIME` below if a different
// default suits your team.

const DEFAULT_TIME = '09:00:00';

const csvBuffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const csv = csvBuffer.toString('utf8');
const lines = csv.split(/\r?\n/).filter((l) => l.length > 0);
if (lines.length < 2) return [];

function parseLine(line) {
  const out = [];
  let cur = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (inQuotes) {
      if (c === '"' && line[i + 1] === '"') { cur += '"'; i++; }
      else if (c === '"') { inQuotes = false; }
      else { cur += c; }
    } else if (c === '"') {
      inQuotes = true;
    } else if (c === ',') {
      out.push(cur); cur = '';
    } else {
      cur += c;
    }
  }
  out.push(cur);
  return out;
}

const header = parseLine(lines[0]).map((h) => h.trim());
const idx = (n) => header.findIndex((h) => h.toLowerCase() === n);
const iCompany = idx('location_id');
const iDate = idx('date');
const iOrder = idx('order');
const iName = idx('location_name');
const iTerritory = idx('territory');
const iTier = idx('tier');

if (iCompany === -1) throw new Error('Schedule CSV is missing a `location_id` column.');
if (iDate === -1) throw new Error('Schedule CSV is missing a `date` column.');

const out = [];
for (let i = 1; i < lines.length; i++) {
  const cells = parseLine(lines[i]);
  const companyId = (cells[iCompany] ?? '').trim();
  const date = (cells[iDate] ?? '').trim();
  if (!companyId || !date) continue;

  const raw = {};
  for (let j = 0; j < header.length; j++) raw[header[j]] = cells[j];

  const epochMs = new Date(`${date}T${DEFAULT_TIME}`).getTime();

  const name = iName !== -1 ? (cells[iName] || '').trim() : '';
  const order = iOrder !== -1 ? (cells[iOrder] || '').trim() : '';
  const territory = iTerritory !== -1 ? (cells[iTerritory] || '').trim() : '';
  const tier = iTier !== -1 ? (cells[iTier] || '').trim() : '';

  const subjectName = name || companyId;
  const subject = order
    ? `Ramsisa visit #${order}: ${subjectName}`
    : `Ramsisa visit: ${subjectName}`;

  out.push({
    json: {
      company_id: companyId,
      date,
      order,
      territory,
      tier,
      epoch_ms: epochMs,
      subject,
      raw,
    },
  });
}

if (out.length === 0) throw new Error('Schedule CSV had a header but no rows.');
return out;
